import "./styles.css";
import { BrowserRouter, Routes, Route } from "react-router-dom";


import Buttons from "./Buttons";
import IssueCardDemo from "./Issue-Card";
import CompareCardDemo from "./Compare-Card";

export default function App() {
  return (
    <div>
      <Routes>
      <div class="mb-4 flex items-center"><a class="flex h-7 items-center justify-center rounded-full px-4 text-center text-sm transition-colors hover:text-primary bg-muted font-medium text-primary" href="/examples/mail">Mail</a><a class="flex h-7 items-center justify-center rounded-full px-4 text-center text-sm transition-colors hover:text-primary text-muted-foreground" href="/examples/dashboard">Dashboard</a><a class="flex h-7 items-center justify-center rounded-full px-4 text-center text-sm transition-colors hover:text-primary text-muted-foreground" href="/examples/cards">Cards</a><a class="flex h-7 items-center justify-center rounded-full px-4 text-center text-sm transition-colors hover:text-primary text-muted-foreground" href="/examples/tasks">Tasks</a><a class="flex h-7 items-center justify-center rounded-full px-4 text-center text-sm transition-colors hover:text-primary text-muted-foreground" href="/examples/playground">Playground</a><a class="flex h-7 items-center justify-center rounded-full px-4 text-center text-sm transition-colors hover:text-primary text-muted-foreground" href="/examples/forms">Forms</a><a class="flex h-7 items-center justify-center rounded-full px-4 text-center text-sm transition-colors hover:text-primary text-muted-foreground" href="/examples/music">Music</a><a class="flex h-7 items-center justify-center rounded-full px-4 text-center text-sm transition-colors hover:text-primary text-muted-foreground" href="/examples/authentication">Authentication</a></div>
          <Route path="/" exact element={<CompareCardDemo />} />
          <Route path="buttons" element={<Buttons />} />
          <Route path="issues" element={<IssueCardDemo />} />
          <Route path="*" element={<div>No Page</div>} />
      </Routes>

    </div>
  );
}
